import re
from pathlib import Path

AC_UID = "score_rebalance_01"
AC_TYPE = "data"

SCRIPT = Path(__file__).resolve().parents[3] / "scripts" / "score-update.sh"


def _parse_event_deltas():
    """Extract the EVENT_DELTAS dict literal from score-update.sh."""
    text = SCRIPT.read_text()
    m = re.search(r"EVENT_DELTAS\s*=\s*\{(.*?)^\}", text, re.DOTALL | re.MULTILINE)
    assert m, "EVENT_DELTAS dict block not found"
    block = m.group(1)
    # Each entry shape: 'event_name': {'dev': N, 'ba': N, 'qa': N},
    entries = re.findall(
        r"""["']([^"']+)["']\s*:\s*\{\s*["']dev["']\s*:\s*(-?\d+)\s*,\s*["']ba["']\s*:\s*(-?\d+)\s*,\s*["']qa["']\s*:\s*(-?\d+)\s*\}""",
        block,
    )
    return {name: {"dev": int(d), "ba": int(b), "qa": int(q)} for name, d, b, q in entries}


def test_AC_01():
    """
    GIVEN: scripts/score-update.sh is read and EVENT_DELTAS dict is parsed
    WHEN:  all positive delta values are enumerated across all events and all agent roles
    THEN:  max positive delta is +5; all negative deltas identical to pre-change values;
           specific values match: close_success_qa_pass={dev:5,ba:3,qa:3}, etc.
    """
    deltas = _parse_event_deltas()
    all_values = [v for ev in deltas.values() for v in ev.values()]
    positive = [v for v in all_values if v > 0]
    negative = [v for v in all_values if v < 0]
    assert max(positive) == 5, f"max positive delta should be 5, got {max(positive)}"
    assert min(negative) == -40, f"min negative delta should be -40, got {min(negative)}"
    # Exact spec values:
    assert deltas["close_success_qa_pass"] == {"dev": 5, "ba": 3, "qa": 3}
    assert deltas["close_success_qa_fail_fixed"] == {"dev": 5, "ba": 3, "qa": 2}
    assert deltas["qa_first_pass"] == {"dev": 2, "ba": 1, "qa": 0}
    assert deltas["qa_second_pass"] == {"dev": 1, "ba": 0, "qa": 0}
    assert deltas["user_rating_5"] == {"dev": 1, "ba": 0, "qa": 0}
